import React, { useState } from 'react';
import './contactform.css';
import { useNavigate } from 'react-router-dom';

const API_BASE_URL = 'https://e-nutritionist-9bb9c8f7b2bc.herokuapp.com';
const API_LOCAL_HOST = "http://localhost:3000";

const ContactForm = () => {
  const navigate = useNavigate();
  const API_URL = API_LOCAL_HOST; // Update this conditionally based on the environment

  const [formData, setFormData] = useState({
    name: "",
    phone_number: "", // Ensure this matches the backend's expected parameter name
    email: "",
    message: ""
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({
      ...formData,
      [name]: value
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
  
    try {
      const response = await fetch(`${API_URL}/contact_messages`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ contact_message: formData }), // Correctly wrapped in `contact_message`
      });
  
      // Check if the response's content type is JSON
      const contentType = response.headers.get('Content-Type');
      if (contentType && contentType.includes('application/json')) {
        const result = await response.json();
  
        if (response.ok) {
          alert(result.message || 'Message sent successfully!');
          setFormData({
            name: "",
            phone_number: "",
            email: "",
            message: ""
          });
          navigate("/thankyoumessage");
        } else {
          // Handle error response
          alert('Error: ' + (result.errors ? result.errors.join(', ') : result.error || 'Unknown error'));
        }
      } else {
        // Handle unexpected content type
        const textResponse = await response.text();
        console.error('Unexpected response format:', textResponse);
        alert('Unexpected response format. Please try again later.');
      }
    } catch (error) {
      console.error('Error:', error);
      alert('There was an error sending your message. Please try again later.');
    }
  };
  

  return (
    <div className="contact-form-container-outer">
      <div className="contact-form-container">
        <h2>Share anything with us</h2>
        <form className="contact-form" onSubmit={handleSubmit}>
          <label>
            Name:
            <input
              type="text"
              name="name"
              value={formData.name}
              onChange={handleChange}
              required
            />
          </label>
          <label>
            Phone:
            <input
              type="tel"
              name="phone_number" // Matching the backend expectation
              value={formData.phone_number}
              onChange={handleChange}
              required
            />
          </label>
          <label>
            Email:
            <input
              type="email"
              name="email"
              value={formData.email}
              onChange={handleChange}
              required
            />
          </label>
          <label>
            Message:
            <textarea
              name="message"
              value={formData.message}
              onChange={handleChange}
              required
            ></textarea>
          </label>
          <button type="submit">Submit</button>
        </form>
      </div>
    </div>
  );
};

export default ContactForm;
